class Solution:
    def maxProfit(self, prices: List[int]) -> int:
        hold, sold, rest = -10**18, 0, 0
        for p in prices:
            prev_hold = hold
            hold = max(hold, rest - p)
            sold = prev_hold + p
            rest = max(rest, sold)
        return max(rest, sold)

