class Solution {
public:
    int maxProfit(vector<int>& prices) {
        long long hold = LLONG_MIN/2, sold = 0, rest = 0;
        for (int p : prices) {
            long long ph = hold;
            hold = max(hold, rest - p);
            sold = ph + p;
            rest = max(rest, sold);
        }
        return max(rest, sold);
    }
};

