int maxProfit(int* prices, int n) {
    long long hold = -1e18, sold = 0, rest = 0;
    for (int i = 0; i < n; i++) {
        long long ph = hold;
        hold = hold > rest - prices[i] ? hold : rest - prices[i];
        sold = ph + prices[i];
        rest = rest > sold ? rest : sold;
    }
    return (int)(rest > sold ? rest : sold);
}
